	(10, "tiless", "<p>floor</p>", NULL, 75, "gurudev", "open", 0, 6, "2025-12-25 07:19:25", "2025-12-31 13:38:01"),
	(13, "New Test Project", "<p><strong style=\"color: rgb(230, 0, 0);\">This is the test project</strong></p>", NULL, 570, "Kanpur Ngar", "open", 0, 6, "2025-12-31 14:01:41", "2025-12-31 14:01:41"),
	(14, "Phases of Construction Projects", "<p>Construction Project Management (CPM) is&nbsp;the professional discipline of overseeing a building project from start to finish, applying project management principles to control its&nbsp;<strong>scope,&nbsp;</strong><a href=\"https://www.google.com/search?q=cost&amp;rlz=1C1CHBF_enIN1141IN1141&amp;oq=construction+project&amp;gs_lcrp=EgZjaHJvbWUqCggAEAAYsQMYgAQyCggAEAAYsQMYgAQyBwgBEAAYgAQyBggCEEUYOTIHCAMQABiABDIHCAQQABiABDIHCAUQABiABDIHCAYQABiABDIGCAcQRRg80gEINjE1MmowajeoAgCwAgA&amp;sourceid=chrome&amp;ie=UTF-8&amp;ved=2ahUKEwj7gefZo-iRAxVxTWcHHRegN1UQgK4QegYIAQgAEAY\" target=\"_blank\" style=\"color: unset;\"><strong>cost</strong></a><strong>, time,&nbsp;</strong><a href=\"https://www.google.com/search?q=quality&amp;rlz=1C1CHBF_enIN1141IN1141&amp;oq=construction+project&amp;gs_lcrp=EgZjaHJvbWUqCggAEAAYsQMYgAQyCggAEAAYsQMYgAQyBwgBEAAYgAQyBggCEEUYOTIHCAMQABiABDIHCAQQABiABDIHCAUQABiABDIHCAYQABiABDIGCAcQRRg80gEINjE1MmowajeoAgCwAgA&amp;sourceid=chrome&amp;ie=UTF-8&amp;ved=2ahUKEwj7gefZo-iRAxVxTWcHHRegN1UQgK4QegYIAQgAEAc\" target=\"_blank\" style=\"color: unset;\"><strong>quality</strong></a><strong>,&nbsp;</strong><a href=\"https://www.google.com/search?q=safety&amp;rlz=1C1CHBF_enIN1141IN1141&amp;oq=construction+project&amp;gs_lcrp=EgZjaHJvbWUqCggAEAAYsQMYgAQyCggAEAAYsQMYgAQyBwgBEAAYgAQyBggCEEUYOTIHCAMQABiABDIHCAQQABiABDIHCAUQABiABDIHCAYQABiABDIGCAcQRRg80gEINjE1MmowajeoAgCwAgA&amp;sourceid=chrome&amp;ie=UTF-8&amp;ved=2ahUKEwj7gefZo-iRAxVxTWcHHRegN1UQgK4QegYIAQgAEAg\" target=\"_blank\" style=\"color: unset;\"><strong>safety</strong></a><strong>, and&nbsp;</strong><a href=\"https://www.google.com/search?q=function&amp;rlz=1C1CHBF_enIN1141IN1141&amp;oq=construction+project&amp;gs_lcrp=EgZjaHJvbWUqCggAEAAYsQMYgAQyCggAEAAYsQMYgAQyBwgBEAAYgAQyBggCEEUYOTIHCAMQABiABDIHCAQQABiABDIHCAUQABiABDIHCAYQABiABDIGCAcQRRg80gEINjE1MmowajeoAgCwAgA&amp;sourceid=chrome&amp;ie=UTF-8&amp;ved=2ahUKEwj7gefZo-iRAxVxTWcHHRegN1UQgK4QegYIAQgAEAk\" target=\"_blank\" style=\"color: unset;\"><strong>function</strong></a>. It involves planning, designing, procuring, constructing, and handing over a project, coordinating diverse stakeholders like architects, engineers, and contractors, ensuring the final build meets client needs while managing resources efficiently.&nbsp;</p><p>Key Aspects of CPM</p><ul><li><strong>Project Lifecycle:</strong>&nbsp;Covers all stages, from initial concept and feasibility studies to demolition or maintenance.</li><li><strong>Core Responsibilities:</strong>&nbsp;Budgeting, scheduling, risk assessment, resource allocation, communication, and quality control.</li><li><strong>Stakeholder Management:</strong>&nbsp;Acts as the central point of contact, coordinating owners, designers, suppliers, and trades.</li><li><strong>Tools &amp; Techniques:</strong>&nbsp;Utilizes methodologies like&nbsp;<a href=\"https://www.google.com/search?q=Lean+Project+Delivery&amp;rlz=1C1CHBF_enIN1141IN1141&amp;oq=construction+project&amp;gs_lcrp=EgZjaHJvbWUqCggAEAAYsQMYgAQyCggAEAAYsQMYgAQyBwgBEAAYgAQyBggCEEUYOTIHCAMQABiABDIHCAQQABiABDIHCAUQABiABDIHCAYQABiABDIGCAcQRRg80gEINjE1MmowajeoAgCwAgA&amp;sourceid=chrome&amp;ie=UTF-8&amp;ved=2ahUKEwj7gefZo-iRAxVxTWcHHRegN1UQgK4QegYIAQgCEAE\" target=\"_blank\" style=\"color: unset;\">Lean Project Delivery</a>&nbsp;and technologies like&nbsp;<a href=\"https://www.google.com/search?q=Building+Information+Modeling+%28BIM%29&amp;rlz=1C1CHBF_enIN1141IN1141&amp;oq=construction+project&amp;gs_lcrp=EgZjaHJvbWUqCggAEAAYsQMYgAQyCggAEAAYsQMYgAQyBwgBEAAYgAQyBggCEEUYOTIHCAMQABiABDIHCAQQABiABDIHCAUQABiABDIHCAYQABiABDIGCAcQRRg80gEINjE1MmowajeoAgCwAgA&amp;sourceid=chrome&amp;ie=UTF-8&amp;ved=2ahUKEwj7gefZo-iRAxVxTWcHHRegN1UQgK4QegYIAQgCEAI\" target=\"_blank\" style=\"color: unset;\">Building Information Modeling (BIM)</a>.</li></ul><p><br></p>", NULL, 1655, "Kanpur Nagar", "awarded", 0, 6, "2025-12-31 16:48:19", "2026-01-10 05:06:05"),
	(15, "kkk", "<p>mmmm</p>", NULL, 180, NULL, "open", 0, 16, "2026-01-06 10:21:11", "2026-01-06 10:21:11"),
